1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_SURCHARGE = 0.1;
7	const CURSED_SURCHARGE = 0.5;
8	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
9	const HIGH_ENCHANTMENT_THRESHOLD = 5;
10	
11	const BASE_PREMIUMS: Record<string, number> = {
12	  sword: 100,
13	  amulet: 60,
14	  staff: 80,
15	  potion: 40,
16	  rune: 25,
17	  moonstone: 25,
18	};
19	
20	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
21	const BLOCK_BASE = 60;
22	const BLOCK_SIZE = 3;
23	const LOYALTY_YEARS_THRESHOLD = 2;
24	const LOYALTY_DISCOUNT_RATE = 0.2;
25	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
26	
27	function withFirstInsurance(base: number): number {
28	  return base + base * FIRST_INSURANCE_SURCHARGE;
29	}
30	
31	function itemBase(item: Item): number {
32	  return BASE_PREMIUMS[item.type];
33	}
34	
35	function groupByType(items: Item[]): Map<string, Item[]> {
36	  const groups = new Map<string, Item[]>();
37	  for (const item of items) {
38	    const list = groups.get(item.type) ?? [];
39	    list.push(item);
40	    groups.set(item.type, list);
41	  }
42	  return groups;
43	}
44	
45	function componentGroupBase(group: Item[]): number {
46	  const blocks = Math.floor(group.length / BLOCK_SIZE);
47	  const remainder = group.length - blocks * BLOCK_SIZE;
48	  return blocks * BLOCK_BASE + remainder * itemBase(group[0]);
49	}
50	
51	function surchargeWhen(condition: boolean, base: number, rate: number): number {
52	  return condition ? base * rate : 0;
53	}
54	
55	function itemPremium(item: Item): number {
56	  const base = itemBase(item);
57	  const isHighlyEnchanted = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
58	  const curseSurcharge = surchargeWhen(item.cursed === true, base, CURSED_SURCHARGE);
59	  const enchantmentSurcharge = surchargeWhen(isHighlyEnchanted, base, HIGH_ENCHANTMENT_SURCHARGE);
60	  return withFirstInsurance(base) + curseSurcharge + enchantmentSurcharge;
61	}
62	
63	function partitionItems(items: Item[]): { components: Item[]; others: Item[] } {
64	  const components: Item[] = [];
65	  const others: Item[] = [];
66	  for (const item of items) {
67	    (COMPONENT_TYPES.has(item.type) ? components : others).push(item);
68	  }
69	  return { components, others };
70	}
71	
72	function componentGroupBases(components: Item[]): number[] {
73	  const bases: number[] = [];
74	  for (const [, group] of groupByType(components)) {
75	    bases.push(componentGroupBase(group));
76	  }
77	  return bases;
78	}
79	
80	function quotePremium(items: Item[], yearsWithMHPCO: number, isFirstContract: boolean): number {
81	  const { components, others } = partitionItems(items);
82	  const groupBases = componentGroupBases(components);
83	  const othersTotal = others.reduce((sum, item) => sum + itemPremium(item), 0);
84	  const componentsTotal = groupBases.reduce(
85	    (sum, base) => sum + withFirstInsurance(base),
86	    0,
87	  );
88	  const policyBase =
89	    others.reduce((sum, item) => sum + itemBase(item), 0) +
90	    groupBases.reduce((sum, base) => sum + base, 0);
91	  const loyaltyDiscount = surchargeWhen(
92	    yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD,
93	    policyBase,
94	    LOYALTY_DISCOUNT_RATE,
95	  );
96	  const followUpDiscount = surchargeWhen(
97	    !isFirstContract,
98	    policyBase,
99	    FOLLOW_UP_DISCOUNT_RATE,
100	  );
101	  return Math.ceil(othersTotal + componentsTotal - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
102	}
103	
104	export function runScenario(scenario: Scenario): { results: { premium: number }[] } {
105	  const results = scenario.steps.map((step, index) => ({
106	    premium: quotePremium(step.items, scenario.customer.yearsWithMHPCO, index === 0),
107	  }));
108	  return { results };
109	}
